class Solution:
    def maxPalindromes(self, s: str, k: int) -> int:
        n = len(s)
        dp = [[False]*n for _ in range(n)]
        for i in range(n-1, -1, -1):
            for j in range(i, n):
                if s[i] == s[j] and (j-i <= 2 or dp[i+1][j-1]):
                    dp[i][j] = True
        res = 0
        last = -1
        for i in range(n):
            for j in range(i+k-1, n):
                if dp[i][j] and i > last:
                    res += 1
                    last = j
                    break
        return res
```
